import Vue from "vue";
import VueRouter from "vue-router";
import TopPage from "@/views/TopPage";

Vue.use(VueRouter);

const routes = [
  {
    path: "/",
    name: "TopPage",
    component: TopPage
  },
  {
    path: "/sample",
    name: "SamplePage",
    component: () => import("@/components/sample/Content1")
  }
];

const router = new VueRouter({
  mode: "history",
  base: process.env.BASE_URL,
  routes
});

export default router;
